# test_final_state.py
import os
import re

def test_result_file_exists_and_correct():
    """Verify that the result file was generated by the mock server and contains the correct token."""
    result_file = "/home/user/result.txt"
    assert os.path.isfile(result_file), "The file /home/user/result.txt does not exist. Did the script run successfully?"

    with open(result_file, "r") as f:
        content = f.read().strip()

    assert content == "SUCCESS_84729_SECURE_EVAL", f"The content of /home/user/result.txt is incorrect. Found: {content}"

def test_python_script_secure():
    """Verify that the Python script exists and does not use eval() or exec()."""
    script_file = "/home/user/fetch_limits.py"
    assert os.path.isfile(script_file), "The Python script /home/user/fetch_limits.py does not exist."

    with open(script_file, "r") as f:
        content = f.read()

    assert not re.search(r'\beval\s*\(', content), "The script contains 'eval(', which is forbidden by the security constraint."
    assert not re.search(r'\bexec\s*\(', content), "The script contains 'exec(', which is forbidden by the security constraint."